    74→/// Slate a new Pace
    75→///
    76→/// Adds a new Pace to a Heat with an initial Tack in rough state.
    77→/// Positioning: use before/after/first to insert at specific location.
    78→pub fn jjrg_slate(gallops: &mut jjrg_Gallops, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
    79→    // Validate silks is kebab-case
    80→    if !zjjrg_is_kebab_case(&args.silks) {
    81→        return Err(format!("silks must be kebab-case, got '{}'", args.silks));
    82→    }
    83→
    84→    // Validate text is non-empty
    85→    if args.text.is_empty() {
    86→        return Err("text must not be empty".to_string());
    87→    }
    88→
    89→    // Validate positioning mutual exclusivity
    90→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
    91→        .iter()
    92→        .filter(|&&x| x)
    93→        .count();
    94→    if position_count > 1 {
    95→        return Err("Only one of --before, --after, or --first may be specified".to_string());
    96→    }
    97→
    98→    // Parse and normalize firemark
    99→    let firemark = Firemark::jjrf_parse(&args.firemark)
   100→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   101→    let firemark_key = firemark.jjrf_display();
   102→
   103→    // Verify Heat exists
   104→    let heat = gallops.heats.get_mut(&firemark_key)
   105→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   106→
   107→    // If --before or --after specified, validate target coronet exists
   108→    let insert_position = if let Some(ref before_str) = args.before {
   109→        let target = Coronet::jjrf_parse(before_str)
   110→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   111→        let target_key = target.jjrf_display();
   112→        let pos = heat.order.iter().position(|c| c == &target_key)
   113→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   114→        Some(pos) // Insert before this position
   115→    } else if let Some(ref after_str) = args.after {
   116→        let target = Coronet::jjrf_parse(after_str)
   117→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   118→        let target_key = target.jjrf_display();
   119→        let pos = heat.order.iter().position(|c| c == &target_key)
   120→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   121→        Some(pos + 1) // Insert after this position
   122→    } else if args.first {
   123→        Some(0) // Insert at beginning
   124→    } else {
   125→        None // Append to end (default)
   126→    };
   127→
   128→    // Construct Coronet
   129→    let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   130→
   131→    // Create initial Tack and Pace
   132→    let tack = jjrg_make_tack(
   133→        jjrg_PaceState::Rough,
   134→        args.text,
   135→        args.silks,
   136→        None,
   137→    );
   138→    let pace = jjrg_Pace {
   139→        tacks: vec![tack],
   140→    };
   141→
   142→    // Insert into order at determined position
   143→    match insert_position {
   144→        Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   145→        None => heat.order.push(coronet_str.clone()),
   146→    }
   147→    heat.paces.insert(coronet_str.clone(), pace);
   148→
   149→    // Increment next_pace_seed
   150→    heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   151→
   152→    Ok(jjrg_SlateResult { coronet: coronet_str })
   153→}
