   541→/// Retire a Heat
   542→///
   543→/// Creates trophy file, removes heat from gallops, deletes paddock file.
   544→/// Does NOT save gallops or commit - caller is responsible for that.
   545→pub fn jjrg_retire(
   546→    gallops: &mut jjrg_Gallops,
   547→    args: jjrg_RetireArgs,
   548→    base_path: &Path,
   549→    steeplechase: &[SteeplechaseEntry],
   550→) -> Result<jjrg_RetireResult, String> {
   551→    // Parse and normalize firemark
   552→    let firemark = Firemark::jjrf_parse(&args.firemark)
   553→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   554→    let firemark_key = firemark.jjrf_display();
   555→
   556→    // Validate today is YYMMDD
   557→    if !zjjrg_is_yymmdd(&args.today) {
   558→        return Err(format!("today must be YYMMDD format, got '{}'", args.today));
   559→    }
   560→
   561→    // Verify heat exists
   562→    let heat = gallops.heats.get(&firemark_key)
   563→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   564→
   565→    // Read paddock content before we remove anything
   566→    let paddock_path = base_path.join(&heat.paddock_file);
   567→    let paddock_content = fs::read_to_string(&paddock_path)
   568→        .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
   569→
   570→    // Build trophy content
   571→    let trophy_content = zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
   572→
   573→    // Compute trophy path: .claude/jjm/retired/jjh_b<created>-r<today>-<silks>.md
   574→    let trophy_filename = format!(
   575→        "jjh_b{}-r{}-{}.md",
   576→        heat.creation_time,
   577→        args.today,
   578→        heat.silks
   579→    );
   580→    let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
   581→    let trophy_full_path = base_path.join(&trophy_rel_path);
   582→
   583→    // Create retired directory if needed
   584→    if let Some(parent) = trophy_full_path.parent() {
   585→        fs::create_dir_all(parent)
   586→            .map_err(|e| format!("Failed to create retired directory: {}", e))?;
   587→    }
   588→
   589→    // Write trophy file
   590→    fs::write(&trophy_full_path, trophy_content)
   591→        .map_err(|e| format!("Failed to write trophy file: {}", e))?;
   592→
   593→    // Capture info for result before removing heat
   594→    let silks = heat.silks.clone();
   595→    let paddock_file = heat.paddock_file.clone();
   596→
   597→    // Remove heat from gallops (do NOT change next_heat_seed)
   598→    // Use shift_remove to preserve order of remaining heats
   599→    gallops.heats.shift_remove(&firemark_key);
   600→
   601→    // Delete paddock file
   602→    if paddock_path.exists() {
   603→        fs::remove_file(&paddock_path)
   604→            .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
   605→    }
   606→
   607→    Ok(jjrg_RetireResult {
   608→        trophy_path: trophy_rel_path,
   609→        paddock_path: paddock_file,
   610→        silks,
   611→        firemark: firemark_key,
   612→    })
   613→}
