   856→/// Garland a Heat - celebrate completion and create continuation
   857→///
   858→/// Updates source heat silks to garlanded form and status to stabled.
   859→/// Creates new heat with continuation silks, status racing.
   860→/// Transfers actionable paces (rough/bridled) to new heat.
   861→/// Retains complete/abandoned paces in garlanded heat.
   862→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
   863→    use crate::jjrc_core::jjrc_timestamp_from_env;
   864→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
   865→
   866→    // Parse and normalize firemark
   867→    let firemark = Firemark::jjrf_parse(&args.firemark)
   868→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   869→    let firemark_key = firemark.jjrf_display();
   870→
   871→    // Verify source heat exists and extract needed data (avoid holding the borrow)
   872→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
   873→        let source_heat = gallops.heats.get(&firemark_key)
   874→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   875→
   876→        // Parse source silks to determine sequence
   877→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
   878→        let seq = sequence.unwrap_or(1);
   879→
   880→        // Count actionable paces
   881→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
   882→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   883→                if let Some(tack) = pace.tacks.first() {
   884→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   885→                } else {
   886→                    false
   887→                }
   888→            } else {
   889→                false
   890→            }
   891→        }).count();
   892→
   893→        // Validate there are actionable paces to transfer
   894→        if actionable_count == 0 {
   895→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
   896→        }
   897→
   898→        // Count retained paces
   899→        let retained_count = source_heat.paces.len() - actionable_count;
   900→
   901→        // Count complete paces for steeplechase marker
   902→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
   903→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   904→                if let Some(tack) = pace.tacks.first() {
   905→                    tack.state == jjrg_PaceState::Complete
   906→                } else {
   907→                    false
   908→                }
   909→            } else {
   910→                false
   911→            }
   912→        }).count();
   913→
   914→        // Create steeplechase marker entry
   915→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
   916→
   917→        // Update source heat: add steeplechase marker (prepend to paddock file)
   918→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
   919→        let existing_content = std::fs::read_to_string(&source_paddock_path)
   920→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   921→
   922→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
   923→        std::fs::write(&source_paddock_path, updated_content)
   924→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   925→
   926→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
   927→    };
   928→
   929→    // Build garlanded and continuation silks
   930→    let (base, seq) = source_silks;
   931→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
   932→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
   933→
   934→    // Nominate new heat with continuation silks
   935→    let created_ts = jjrc_timestamp_from_env();
   936→    let nominate_args = jjrg_NominateArgs {
   937→        silks: continuation_silks.clone(),
   938→        created: created_ts,
   939→    };
   940→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
   941→    let new_firemark_key = nominate_result.firemark.clone();
   942→
   943→    // Get destination heat paddock file for copy
   944→    let dest_paddock_file = {
   945→        let dest_heat = gallops.heats.get(&new_firemark_key)
   946→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
   947→        dest_heat.paddock_file.clone()
   948→    };
   949→
   950→    // Read original paddock content before modifications (for new heat)
   951→    let source_paddock_path = base_path.join(&source_paddock_file);
   952→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
   953→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   954→
   955→    // Extract original content (removing marker we just added)
   956→    let existing_content = original_paddock_content.split_once("\n\n")
   957→        .map(|(_, rest)| rest)
   958→        .unwrap_or(&original_paddock_content);
   959→
   960→    // Copy paddock content from source to new heat
   961→    let dest_paddock_path = base_path.join(&dest_paddock_file);
   962→    std::fs::write(&dest_paddock_path, existing_content)
   963→        .map_err(|e| format!("Failed to copy paddock to new heat: {}", e))?;
   964→
   965→    // Draft all actionable paces to new heat (in order)
   966→    for coronet_key in source_order {
   967→        if let Some(pace) = gallops.heats.get(&firemark_key).unwrap().paces.get(&coronet_key) {
   968→            if let Some(tack) = pace.tacks.first() {
   969→                if matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled) {
   970→                    // Draft this pace to new heat (append to end)
   971→                    let draft_args = jjrg_DraftArgs {
   972→                        coronet: coronet_key.clone(),
   973→                        to: new_firemark_key.clone(),
   974→                        before: None,
   975→                        after: None,
   976→                        first: false, // Append to end to maintain order
   977→                    };
   978→                    jjrg_draft(gallops, draft_args)?;
   979→                }
   980→            }
   981→        }
   982→    }
   983→
   984→    // Update source heat: change silks to garlanded, set status to stabled
   985→    let source_heat_mut = gallops.heats.get_mut(&firemark_key).unwrap();
   986→    source_heat_mut.silks = garlanded_silks.clone();
   987→    source_heat_mut.status = jjrg_HeatStatus::Stabled;
   988→
   989→    // Set new heat status to racing and move to front
   990→    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
   991→    new_heat_mut.status = jjrg_HeatStatus::Racing;
   992→    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
   993→        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
   994→    }
   995→
   996→    Ok(jjrg_GarlandResult {
   997→        old_firemark: firemark_key,
   998→        old_silks: garlanded_silks,
   999→        new_firemark: new_firemark_key,
  1000→        new_silks: continuation_silks,
  1001→        paces_transferred: actionable_count,
  1002→        paces_retained: retained_count,
